  dct:source narr:Sample_BudgetJustificationHiddenCriterion ;
  skos:broader narr:ProblemStakes ;
  skos:note "Equipment should be justified by a specific capability gap, not generic need. Example: 'the nearest accessible instrument is 200 miles away and our samples degrade within 4 hours' is a strong justification; 'we need a mass spec' is not." ;
  narr:theme "Equipment budget lines must be justified by a specific capability gap, not generic need statements" .

